#!/bin/bash
set -euo pipefail

cd /workspace/effect

# Idempotency guard - bail out if patch already applied
if grep -q 'Arr.NonEmptyArray<string>' packages/cluster/src/MessageStorage.ts 2>/dev/null; then
    echo "Patch already applied, skipping."
    exit 0
fi

# Gold patch is base64-encoded so trailing whitespace on context lines is preserved
echo '' | base64 -d | git apply

echo "Gold patch applied successfully."
